function buildFeatureVector(band, mode, distance, partitionAmount, material) {
  // One-hot encode in the same order the encoder used during training
  const x = {
    Distance: distance,
    PartitionAmount: partitionAmount,
  };
  for (const b of CATEGORICAL_LEVELS.PrimaryBand) x[`PrimaryBand_${b}`] = (b === band ? 1 : 0);
  for (const m of CATEGORICAL_LEVELS.Mode)        x[`Mode_${m}`]        = (m === mode ? 1 : 0);
  for (const mat of CATEGORICAL_LEVELS.Material)  x[`Material_${mat}`]  = (mat === material ? 1 : 0);
  return x;
}

export function predict({ band, mode, distance, wallCount, dominantMaterial }) {
  const x = buildFeatureVector(band, mode, distance, wallCount, dominantMaterial);
  const preds = TREES.map(t => t(x));
  const mean = preds.reduce((a, b) => a + b, 0) / preds.length;
  // Uncertainty proxy: tree-prediction standard deviation (epistemic only,
  // not calibrated — see report Section 4.6). For deployment, prefer a
  // conformal wrapper or quantile-forest-based interval.
  const variance = preds.reduce((a, p) => a + (p - mean) ** 2, 0) / preds.length;
  const sd = Math.sqrt(variance);
  return {
    throughput: Math.round(mean),
    uncertainty: Math.round(sd),
    lower: Math.max(0, Math.round(mean - 1.96 * sd)),
    upper: Math.round(mean + 1.96 * sd),
  };
}

export const META = {
  featureNames: FEATURE_NAMES,
  categoricalLevels: CATEGORICAL_LEVELS,
  treeCount: TREES.length,
};
